class SimpleAgent:
    def __init__(self):
        self.tools = {
            'calculator': eval,  # Simple but dangerous in real life!
            'python': lambda code: exec(code) or 'Executed'
        }

    def run(self, query):
        # Simplified: if query has 'calculate', use calculator
        if 'calculate' in query.lower():
            expr = query.split('calculate')[1].strip()
            return str(self.tools['calculator'](expr))
        return 'I dont have a tool for that'

