class SentimentAgent:
    def analyze(self, headlines):
        # Returns sentiment score -100 to +100
        scores = {'ETH upgrade': 80, 'SEC lawsuit': -60, 'bullish': 90}
        return sum(scores.get(h, 0) for h in headlines) / len(headlines)

class TechnicalAgent:
    def analyze(self, price_data):
        # Returns signal: 'buy', 'sell', 'hold'
        rsi = price_data.get('rsi', 50)
        if rsi < 30: return 'buy'  # oversold
        if rsi > 70: return 'sell' # overbought
        return 'hold'

class RiskAgent:
    def check(self, positions, day_pnl):
        # Returns whether trading is allowed
        active_positions = len(positions)
        total_exposure = sum(p['size'] for p in positions)
        if day_pnl <= -100: return False, 'Daily loss limit hit'
        if active_positions >= 3: return False, 'Max 3 positions'
        if total_exposure >= 600: return False, 'Max $600 exposure'
        return True, 'OK'

class SupervisorAgent:
    def decide(self):
        sentiment = SentimentAgent().analyze(news)
        signal = TechnicalAgent().analyze(price)
        risk_ok, reason = RiskAgent().check(positions, day_pnl)

        if not risk_ok:
            log_action('BLOCKED', reason)
            return None  # No trade today

        if sentiment > 50 and signal == 'buy':
            log_action('APPROVED', f'Sentiment={sentiment}, Signal=buy')
            return {'action': 'buy', 'size': min(200, account_balance * 0.1), 'stop_loss': -5%}

        log_action('SKIPPED', f'Sentiment={sentiment}, Signal={signal}')
        return None
```

Why multi-agent? Each agent has one job, tested separately. The supervisor enforces all rules before any action. A bug in SentimentAgent won't let a bad trade through because RiskAgent blocks it. This defense-in-depth protects your $2k.

