import numpy as np
class PolicyGrad:
    def __init__(self): self.W1 = np.random.randn(3,4)*0.1; self.W2 = np.random.randn(4,3)*0.1; self.lr=0.01
    def forward(self,s):
        h=np.tanh(s@self.W1); logits=h@self.W2
        p=np.exp(logits)/np.sum(np.exp(logits)); return p,h
    def update(self,S,A,R):
        G=0; disc=[]
        for r in reversed(R): G=r+0.99*G; disc.insert(0,G)
        disc=(disc-np.mean(disc))/(np.std(disc)+1e-8)
        for s,a,g in zip(S,A,disc):
            p,h=self.forward(s); dl=p.copy(); dl[a]-=1; dl*=g
            self.W2-=self.lr*np.outer(h,dl)
            self.W1-=self.lr*np.outer(s,dl@self.W2.T*(1-h**2))
a=PolicyGrad()
for ep in range(100):
    S,A,R=[],[],[]
    for _ in range(30):
        s=np.random.randn(3); p,h=a.forward(s)
        A.append(np.random.choice([0,1,2],p=p)); S.append(s); R.append(np.random.randn()*10)
    a.update(S,A,R)
