import numpy as np, random
from collections import deque
class DQN:
    def __init__(self):
        self.W1=np.random.randn(3,16)*0.1; self.W2=np.random.randn(16,8)*0.1; self.W3=np.random.randn(8,3)*0.1
        self.tW1,self.tW2,self.tW3=self.W1.copy(),self.W2.copy(),self.W3.copy()
        self.mem=deque(maxlen=1000); self.gamma=0.99
    def forward(self,s,W1,W2,W3): h=np.maximum(0,s@W1); return np.maximum(0,h@W2)@W3
    def act(self,s,e=0.1): return random.choice([0,1,2]) if random.random()<e else np.argmax(self.forward(s,self.W1,self.W2,self.W3))
    def store(self,s,a,r,s2,d): self.mem.append((s,a,r,s2,d))
    def replay(self,b=32):
        if len(self.mem)<b: return
        for s,a,r,s2,d in random.sample(self.mem,b):
            tq=self.forward(s2,self.tW1,self.tW2,self.tW3)
            target=r+(0 if d else self.gamma*np.max(tq))
            q=self.forward(s,self.W1,self.W2,self.W3)
            self.W3+=0.01*(target-q[a])
a=DQN()
for ep in range(200):
    s=np.random.randn(3)
    for _ in range(30): act=a.act(s); s2=np.random.randn(3); a.store(s,act,np.random.randn()*10,s2,False); a.replay(); s=s2
