import requests, numpy as np, time
from transformers import pipeline

sent = pipeline('sentiment-analysis', model='ProsusAI/finbert')

def compute_sentiment(headlines):
    scores = []
    for h in headlines:
        res = sent(h[:512])[0]
        label, score = res['label'], res['score']
        if label == 'positive': scores.append(score)
        elif label == 'negative': scores.append(-score)
        else: scores.append(0)
    return np.mean(scores) if scores else 0

buffer = []
while True:
    news = requests.get('https://cryptopanic.com/api/v1/posts/?auth_token=YOUR_KEY&limit=20').json()
    current = compute_sentiment([p['title'] for p in news['results']])
    buffer.append(current)
    if len(buffer) > 6: buffer.pop(0)
    avg_3h = np.mean(buffer)
    short_30m = np.mean(buffer[-2:]) if len(buffer) >= 2 else current
    print(f'3h avg: {avg_3h:.2f}, 30m avg: {short_30m:.2f}')
    if avg_3h < -0.3 and short_30m > avg_3h + 0.2:
        print('BUY: Sentiment reversal - buy $200 ETH, stop-loss -5%')
    elif avg_3h > 0.5 and short_30m < avg_3h - 0.2:
        print('SELL: Sentiment peaking')
    time.sleep(1800)
